INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f0899a01-moex-00367', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '警察甲之女友乙欲參加某政治集會，甲擔心影響自己前途，不想讓乙與會，遂於乙出發前把大門上鎖，使 乙於集會當時無法離開家中。有關甲之刑責，下列敘述何者正確？', '["甲成立刑法第302條非法剝奪行動自由罪", "甲成立刑法第152條阻止合法之集會罪", "甲成立刑法第305條恐嚇危安罪", "甲成立刑法第294條有義務之遺棄罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00368', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲在有線電視台公然講解上一期六合彩開出的號碼，並預測下一期會有那些明牌會開出，最後並積極勸誘 他人以所報之明牌號碼簽賭。關於此一行為，下列何者正確？', '["甲公然煽惑他人犯賭博罪，成立刑法第153條之煽惑違背法令罪", "甲係賭博罪之教唆犯", "甲之行為受言論自由保障，不成立犯罪", "若確實有人因甲而簽賭，甲才成立犯罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00369', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲酒駕肇事，在警察來之前，遊說乘客乙頂替之。警察來之後，乙自承為肇事者，警察遂於警詢筆錄上記 載乙為肇事者。乙之刑事責任為何？', '["乙成立刑法第185條之3不能安全駕駛罪", "乙成立刑法第164條第2項頂替人犯罪", "乙成立刑法第214條使公務員登載不實罪", "乙不成立犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00370', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列何種情形，不成立脫逃罪？', '["因欠稅而遭行政機關管束之人脫逃", "在監獄中服刑之人脫逃", "經法警持拘票拘提之人脫逃", "羈押中之被告，於羈押期限屆滿，未經合法延長羈押而脫逃"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00371', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列何罪，無結果加重犯之特別規定？', '["刑法第293條無義務之遺棄罪", "刑法第173條之放火罪", "刑法第221條之強制性交罪", "刑法第277條之傷害罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00372', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲把室友乙之封緘信件打開，閱讀完之後發現為看不懂之俄文信，仍予以拍照，重新封緘再放回原處，之 後將該俄文信件照片內容公開於網路尋求翻譯。有關甲之刑事責任，下列敘述何者正確？', '["甲打開封緘信件，即成立刑法第315條妨害書信秘密罪", "甲打開封緘信件，但因信件內容為無法辨識之俄文信，故甲不成立刑法第315條妨害書信秘密罪", "甲拍攝信件之照片，成立刑法第315條之1竊錄他人非公開言論罪", "甲將信件照片公開於網路，成立刑法第315條之2第3項散布竊拍之他人非公開言論罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00373', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲為取得乙對己不利之供述證據，乃約乙至某公園相見談判，期間乙坦承侵占甲新臺幣300萬元，日後一 定會還等語，甲偷偷錄音存證。甲之刑責為何？', '["不成立犯罪", "成立刑法第315條之1竊錄他人非公開言論罪", "成立刑法第315條之2供給場所便利竊錄罪", "成立刑法第315條的妨害書信秘密罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00374', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲、乙為夫妻，某日甲動手毆打乙成傷，乙至地檢署申告，檢察官傳訊當時目睹事發經過之 15歲長子丙 （依法不得命其具結）為證人，檢察官仍命丙具結作證，丙因恐據實陳述必遭甲責駡，於是虛偽證稱：當 時乙自己不小心跌倒，並非遭甲毆打云云。丙的行為應如何評價？', '["偽證罪", "誣告罪", "隱匿他人刑事證據罪", "不成立犯罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00375', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於刑法第168條之偽證罪，下列敘述何者正確？', '["證人於警詢時於案情有重要關係之事項為虛偽陳述，構成偽證罪", "除了證人外，鑑定人、通譯也是偽證罪的行為主體", "有拒絕證言權之證人，縱使依法定程序具結後就案情有重要關係之事項為虛偽陳述，也不會構成偽證罪", "證人因誤會或記憶錯誤而致陳述與事實不符，亦成立本罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00376', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲酒後不能安全駕駛，竟仍超速開車，不慎撞傷前車之駕駛人乙，甲下車發現乙受重傷昏迷，隨即離開現 場，嗣後經路人救援，乙僥倖未死。甲不成立下列何罪？', '["過失致重傷罪", "肇事逃逸罪", "不能安全駕駛罪", "殺人未遂罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
